def compareVersion(version1: str, version2: str) -> int:
    v1 = version1.split(".")
    v2 = version2.split(".")
    max_len = max(len(v1), len(v2))

    for i in range(max_len):
        num1 = int(v1[i]) if i < len(v1) else 0
        num2 = int(v2[i]) if i < len(v2) else 0
        if num1 < num2:
            return -1
        if num1 > num2:
            return 1

    return 0
